// cipher-finder demo: proof that the FRF substrate composes onto text.
// Caesar shifts are σ-grid candidates; quadgram score is the residual;
// Buleyean fold ranks the keys. The same architecture that deblurs images
// breaks classical ciphers — we just forgot to try text. This test
// encrypts a real English passage with Caesar and Vigenère, runs the
// cipher sieve, and validates recovery through the FRF ensemble.

import { describe, expect, it } from 'vitest';
import {
  breakCaesarCipher,
  breakVigenereCipher,
  forkRaceFoldCipherBreak,
} from '../src/text-cipher-sieve';
import {
  quadgramScore,
  indexOfCoincidence,
  normalize,
} from '../src/english-frequency';

const PLAINTEXT = (
  'IT IS A TRUTH UNIVERSALLY ACKNOWLEDGED THAT A SINGLE MAN IN POSSESSION OF A GOOD ' +
  'FORTUNE MUST BE IN WANT OF A WIFE HOWEVER LITTLE KNOWN THE FEELINGS OR VIEWS OF ' +
  'SUCH A MAN MAY BE ON HIS FIRST ENTERING A NEIGHBOURHOOD THIS TRUTH IS SO WELL FIXED ' +
  'IN THE MINDS OF THE SURROUNDING FAMILIES THAT HE IS CONSIDERED THE RIGHTFUL PROPERTY ' +
  'OF SOME ONE OR OTHER OF THEIR DAUGHTERS'
);

function caesarEncrypt(plaintext: string, shift: number): string {
  const upper = plaintext.toUpperCase().replace(/[^A-Z]/g, '');
  let out = '';
  for (let i = 0; i < upper.length; i++) {
    const p = upper.charCodeAt(i) - 65;
    out += String.fromCharCode(((p + shift) % 26) + 65);
  }
  return out;
}

function vigenereEncrypt(plaintext: string, key: string): string {
  const keyUpper = key.toUpperCase().replace(/[^A-Z]/g, '');
  const ptUpper = plaintext.toUpperCase().replace(/[^A-Z]/g, '');
  let out = '';
  for (let i = 0; i < ptUpper.length; i++) {
    const p = ptUpper.charCodeAt(i) - 65;
    const k = keyUpper.charCodeAt(i % keyUpper.length) - 65;
    out += String.fromCharCode(((p + k) % 26) + 65);
  }
  return out;
}

function shuffledAlphabet(seed: number): string {
  const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
  // deterministic Fisher-Yates with a tiny LCG seeded from `seed`
  let s = (seed * 2654435761) >>> 0;
  for (let i = letters.length - 1; i > 0; i--) {
    s = (s * 1664525 + 1013904223) >>> 0;
    const j = s % (i + 1);
    [letters[i], letters[j]] = [letters[j], letters[i]];
  }
  return letters.join('');
}

function substitute(plaintext: string, key: string): string {
  const upper = plaintext.toUpperCase().replace(/[^A-Z]/g, '');
  let out = '';
  for (let i = 0; i < upper.length; i++) {
    const p = upper.charCodeAt(i) - 65;
    out += key[p];
  }
  return out;
}

function unsubstitute(ciphertext: string, key: string): string {
  // build inverse mapping: ciphertext letter -> plaintext letter
  const inverse = new Array<string>(26);
  for (let i = 0; i < 26; i++) {
    inverse[key.charCodeAt(i) - 65] = String.fromCharCode(65 + i);
  }
  let out = '';
  for (let i = 0; i < ciphertext.length; i++) {
    out += inverse[ciphertext.charCodeAt(i) - 65];
  }
  return out;
}

describe('cipher-finder demo: FRF substrate breaks classical ciphers', () => {
  it('recovers a Caesar shift of 13 (ROT13) on Pride and Prejudice', () => {
    const shift = 13;
    const ciphertext = caesarEncrypt(PLAINTEXT, shift);
    const result = breakCaesarCipher(ciphertext);

    expect(result.shift).toBe(13);
    expect(result.plaintext).toBe(normalize(PLAINTEXT));

    const top3 = result.candidates.slice(0, 3);
    const confidence = top3[0].score - top3[1].score;

    // eslint-disable-next-line no-console
    console.log('[Caesar shift=13 broken]');
    // eslint-disable-next-line no-console
    console.log(`  recovered shift: ${result.shift}`);
    // eslint-disable-next-line no-console
    console.log(`  confidence: ${confidence.toFixed(4)} (best - second-best)`);
    // eslint-disable-next-line no-console
    console.log(
      `  top 3 candidates: shift=${top3[0].shift} (score=${top3[0].score.toFixed(2)}), ` +
        `shift=${top3[1].shift} (score=${top3[1].score.toFixed(2)}), ` +
        `shift=${top3[2].shift} (score=${top3[2].score.toFixed(2)})`,
    );
    // eslint-disable-next-line no-console
    console.log(`  plaintext starts with: "${result.plaintext.slice(0, 16)}..."`);
  });

  it('returns all 26 Caesar candidates ranked, with correct Buleyean weights', () => {
    const shift = 7;
    const ciphertext = caesarEncrypt(PLAINTEXT, shift);
    const result = breakCaesarCipher(ciphertext);

    expect(result.candidates.length).toBe(26);

    // descending by score
    for (let i = 1; i < result.candidates.length; i++) {
      expect(result.candidates[i - 1].score).toBeGreaterThanOrEqual(
        result.candidates[i].score,
      );
    }

    // correct shift at rank 0
    expect(result.candidates[0].shift).toBe(7);

    // Buleyean weight = w(R, v) = R - min(v, R) + 1, R=26 rounds, v=rejection-rank
    // rank 0 -> v=0 -> w = 26 - 0 + 1 = 27
    // rank 25 -> v=25 -> w = 26 - 25 + 1 = 2
    expect(result.candidates[0].buleyWeight).toBe(27);
    expect(result.candidates[25].buleyWeight).toBe(2);
  });

  it("recovers a Vigenère cipher with key 'CIPH' (4 letters)", () => {
    const key = 'CIPH';
    const ciphertext = vigenereEncrypt(PLAINTEXT, key);
    const result = breakVigenereCipher(ciphertext, {
      minKeyLength: 1,
      maxKeyLength: 8,
    });

    expect(result.key).toBe('CIPH');
    expect(result.keyLength).toBe(4);
    expect(result.plaintext.startsWith(normalize(PLAINTEXT).slice(0, 32))).toBe(
      true,
    );

    // eslint-disable-next-line no-console
    console.log("[Vigenère key='CIPH' broken]");
    // eslint-disable-next-line no-console
    console.log(`  recovered key: ${result.key}`);
    // eslint-disable-next-line no-console
    console.log(`  recovered keyLength: ${result.keyLength}`);
    // eslint-disable-next-line no-console
    console.log('  keyLength sweep:');
    for (const cand of result.candidates) {
      // eslint-disable-next-line no-console
      console.log(
        `    L=${cand.keyLength}: IC=${cand.ic.toFixed(4)}, score=${cand.score.toFixed(2)}`,
      );
    }
    // eslint-disable-next-line no-console
    console.log(`  plaintext starts with: "${result.plaintext.slice(0, 16)}..."`);
  });

  it("recovers a Vigenère cipher with key 'GNOSIS' (6 letters)", () => {
    const key = 'GNOSIS';
    const ciphertext = vigenereEncrypt(PLAINTEXT, key);
    const result = breakVigenereCipher(ciphertext, {
      minKeyLength: 1,
      maxKeyLength: 10,
    });

    expect(result.key).toBe('GNOSIS');
    expect(result.keyLength).toBe(6);
    expect(result.plaintext.startsWith(normalize(PLAINTEXT).slice(0, 32))).toBe(
      true,
    );

    // eslint-disable-next-line no-console
    console.log("[Vigenère key='GNOSIS' broken]");
    // eslint-disable-next-line no-console
    console.log(`  recovered key: ${result.key} (length ${result.keyLength})`);
  });

  it('forkRaceFoldCipherBreak picks the correct substitution key from 4 candidates', () => {
    const candidates = [0, 1, 2, 3].map((s) => shuffledAlphabet(s));
    const trueKey = candidates[2];
    const ciphertext = substitute(PLAINTEXT, trueKey);

    const result = forkRaceFoldCipherBreak({
      ciphertext,
      candidateKeys: candidates,
      decrypt: (ct, key) => unsubstitute(ct, key),
      score: (text) => quadgramScore(text),
    });

    expect(result.key).toBe(trueKey);
    expect(result.plaintext).toBe(normalize(PLAINTEXT));

    // eslint-disable-next-line no-console
    console.log('[FRF substitution-cipher break]');
    // eslint-disable-next-line no-console
    console.log(`  correct candidate index: 2`);
    // eslint-disable-next-line no-console
    console.log(`  recovered key matches true key: ${result.key === trueKey}`);
    // eslint-disable-next-line no-console
    console.log(`  winning score: ${result.score.toFixed(2)}`);
  });

  it('Index-of-Coincidence: Caesar preserves IC, Vigenère lowers it', () => {
    const plainNorm = normalize(PLAINTEXT);
    const caesarCt = caesarEncrypt(PLAINTEXT, 5);
    const vigenereCt = vigenereEncrypt(PLAINTEXT, 'CIPHER');

    const icPlain = indexOfCoincidence(plainNorm);
    const icCaesar = indexOfCoincidence(caesarCt);
    const icVigenere = indexOfCoincidence(vigenereCt);

    // Caesar is a monoalphabetic shift — IC is invariant under permutation
    // of the alphabet, so caesar IC must equal plaintext IC exactly.
    expect(Math.abs(icCaesar - icPlain)).toBeLessThan(1e-9);

    // Vigenère smears letter frequencies; English IC ~ 0.067, random ~ 0.0385.
    // A 6-letter key on this passage drops IC well below plaintext.
    expect(icVigenere).toBeLessThan(icPlain);
    expect(icPlain).toBeGreaterThan(icVigenere);

    // sanity: plaintext IC is in the English ballpark
    expect(icPlain).toBeGreaterThan(0.055);
    expect(icPlain).toBeLessThan(0.085);

    // eslint-disable-next-line no-console
    console.log('[IC sanity]');
    // eslint-disable-next-line no-console
    console.log(`  plaintext IC = ${icPlain.toFixed(4)}`);
    // eslint-disable-next-line no-console
    console.log(`  Caesar(5) IC = ${icCaesar.toFixed(4)}`);
    // eslint-disable-next-line no-console
    console.log(`  Vigenere('CIPHER') IC = ${icVigenere.toFixed(4)}`);
  });
});
